  'getObsidianURI': function (folderPath, fileName) {
    let vaultName = Zotero.Prefs.get("ai4paper.obsidianvaultname"),
      baseURI = 'obsidian://open?vault=' + encodeURIComponent(vaultName) + "&file=",
      encodedFile = '',
      obsidianURI = '';
    if (Zotero.isWin) {
      let winVaultSuffix = '\x5c' + vaultName,
        winSuffixIdx = folderPath.indexOf(winVaultSuffix);
      if (winSuffixIdx + winVaultSuffix.length === folderPath.length) {
        encodedFile = encodeURIComponent(fileName);
        obsidianURI = '' + baseURI + encodedFile;
      } else {
        let winVaultPrefix = winVaultSuffix + '\x5c',
          winPrefixIdx = folderPath.indexOf(winVaultPrefix),
          winSubpathStart = winPrefixIdx + winVaultPrefix.length,
          winSubpath = folderPath.substring(winSubpathStart);
        winSubpath = winSubpath.split('\x5c').join('/');
        encodedFile = encodeURIComponent(winSubpath + '/' + fileName);
        obsidianURI = '' + baseURI + encodedFile;
      }
    }
    if (Zotero.isMac || Zotero.isLinux) {
      let macVaultSuffix = '/' + vaultName,
        macSuffixIdx = folderPath.indexOf(macVaultSuffix);
      if (macSuffixIdx + macVaultSuffix.length === folderPath.length) {
        encodedFile = encodeURIComponent(fileName);
        obsidianURI = '' + baseURI + encodedFile;
      } else {
        let macVaultPrefix = macVaultSuffix + '/',
          macPrefixIdx = folderPath.indexOf(macVaultPrefix),
          macSubpathStart = macPrefixIdx + macVaultPrefix.length,
          macSubpath = folderPath.substring(macSubpathStart);
        encodedFile = encodeURIComponent(macSubpath + '/' + fileName);
        obsidianURI = '' + baseURI + encodedFile;
      }
    }
    return obsidianURI;
  },
